async fn test_middleware_body_type() {
    let srv = init_service(
        App::new().service(
            web::resource("/test")
                .wrap_fn(|req, srv| {
                    let fut = srv.call(req);
                    async { Ok(fut.await?.map_into_right_body::<()>()) }
                })
                .route(web::get().to(|| async { "hello" })),
        ),
    )
    .await;

    // test if `try_into_bytes()` is preserved across scope layer
