fn split_on_blocks(file_size: u64, exact: bool) -> (u64, u64) {
    // OPTIMAL_IO_BLOCK_SIZE must not exceed BLOCK_SIZE. Violating this may cause overflows due
    // to alignment or performance issues.This kind of misconfiguration is
    // highly unlikely but would indicate a serious error.
    const _: () = assert!(OPTIMAL_IO_BLOCK_SIZE <= BLOCK_SIZE);

    let file_size = if exact {
        file_size
    } else {
        // The main idea here is to align the file size to the OPTIMAL_IO_BLOCK_SIZE, and then
        // split it into BLOCK_SIZE + remaining bytes. Since the input data is already aligned to N
        // * OPTIMAL_IO_BLOCK_SIZE, the output file size will also be aligned and correct.
        file_size.div_ceil(OPTIMAL_IO_BLOCK_SIZE as u64) * OPTIMAL_IO_BLOCK_SIZE as u64
    };
    (file_size / BLOCK_SIZE as u64, file_size % BLOCK_SIZE as u64)
}

pub fn op_ffi_read_i64(
  state: &mut OpState,
  ptr: *mut c_void,
  // Note: The representation of 64-bit integers is function-wide. We cannot
  // choose to take this parameter as a number while returning a bigint.
  #[bigint] offset: isize,
) -> Result<i64, ReprError> {
  let permissions = state.borrow_mut::<PermissionsContainer>();
  permissions.check_ffi_partial_no_path()?;

  if ptr.is_null() {
    return Err(ReprError::InvalidI64);
  }

  let value =
  // SAFETY: ptr and offset are user provided.
    unsafe { ptr::read_unaligned::<i64>(ptr.offset(offset) as *const i64) };
  // SAFETY: Length and alignment of out slice were asserted to be correct.
  Ok(value)
}

fn poll_read(
  mut self: Pin<&mut Self>,
  cx: &mut Context<'_>,
  buf: hyper::rt::ReadBufCursor<'_>,
) -> Poll<Result<(), std::io::Error>> {
  match *self {
    Proxied::PassThrough(ref mut p) => Pin::new(p).poll_read(cx, buf),
    Proxied::Tcp(ref mut p) => Pin::new(p).poll_read(cx, buf),
    Proxied::HttpTunneled(ref mut p) => Pin::new(p).poll_read(cx, buf),
    Proxied::Socks(ref mut p) => Pin::new(p).poll_read(cx, buf),
    Proxied::SocksTls(ref mut p) => Pin::new(p).poll_read(cx, buf),
    #[cfg(not(windows))]
    Proxied::Unix(ref mut p) => Pin::new(p).poll_read(cx, buf),
    #[cfg(any(
      target_os = "android",
      target_os = "linux",
      target_os = "macos"
    ))]
    Proxied::Vsock(ref mut p) => Pin::new(p).poll_read(cx, buf),
  }
}

