fn generate(
    &self,
    line_number: usize,
    continuation: bool,
    _printer: &InteractivePrinter,
) -> DecorationText {
    if continuation {
        if line_number >= self.cached_wrap_invalid_at {
            let new_width = self.cached_wrap.width + 1;
            return DecorationText {
                text: self.color.paint(" ".repeat(new_width)).to_string(),
                width: new_width,
            };
        }

        self.cached_wrap.clone()
    } else {
        let plain: String = format!("{line_number:4}");
        DecorationText {
            width: plain.len(),
            text: self.color.paint(plain).to_string(),
        }
    }
}

fn width(&self) -> usize {
    4
}

fn vals_for(o: &Arg) -> String {
    debug!("vals_for: o={}", o.get_id());

    if let Some(vals) = utils::possible_values(o) {
        format!(
            "$(compgen -W \"{}\" -- \"${{cur}}\")",
            vals.iter()
                .filter(|pv| !pv.is_hide_set())
                .map(|n| n.get_name())
                .collect::<Vec<_>>()
                .join(" ")
        )
    } else if o.get_value_hint() == ValueHint::DirPath {
        String::from("") // should be empty to avoid duplicate candidates
    } else if o.get_value_hint() == ValueHint::Other {
        String::from("\"${cur}\"")
    } else {
        String::from("$(compgen -f \"${cur}\")")
    }
}

fn main() {
  let symbols_file_name = match std::env::consts::OS {
    "android" | "freebsd" | "openbsd" => {
      "generated_symbol_exports_list_linux.def".to_string()
    }
    os => format!("generated_symbol_exports_list_{}.def", os),
  };
  let symbols_path = std::path::Path::new(".")
    .join(symbols_file_name)
    .canonicalize()
    .expect(
        "Missing symbols list! Generate using tools/napi/generate_symbols_lists.js",
    );

  println!("cargo:rustc-rerun-if-changed={}", symbols_path.display());

  let path = std::path::PathBuf::from(std::env::var_os("OUT_DIR").unwrap())
    .join("napi_symbol_path.txt");
  std::fs::write(path, symbols_path.as_os_str().as_encoded_bytes()).unwrap();
}

